-- Plantillas de notificaciones para el módulo de ofertas laborales y candidaturas
	-- Notificación - Cambio de estado de oferta laboral
	 ('c79e5db6-d89d-487f-a4ff-6e2801f7ade5', NOW(), NOW(), '1', '1', NULL, 'Notificación - Cambio de estado de oferta laboral', 'Plantilla para notificar cambios de estado en ofertas laborales.', 'Cambio de estado de la oferta laboral: $stic_job_offers_name', 'Estimado/a,\r\n\r\nEl estado de la oferta laboral $stic_job_offers_name ha cambiado a $stic_job_offers_status.', 
	 '<p>Estimado/a,</p>
	 <p>El estado de la oferta laboral <strong>$stic_job_offers_name</strong> ha cambiado a <strong><span style="background-color: #f1c40f;">$stic_job_offers_status</span></strong></p>',
	 0, '1', 0, 'notification'),
	 -- Notificación - Cambio de estado de candidatura
	 ('8ec00c6b-6102-4eb4-a601-7cdb420676a3', NOW(), NOW(), '1', '1', NULL, 'Notificación - Cambio de estado de candidatura', 'Plantilla por defecto para notificar cambios de estado en candidaturas.', 'Cambio de estado de la candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $contact_full_name:\r\n\r\nSe ha cambiado el estado de su candidatura para la oferta laboral $stic_job_applications_stic_job_applications_stic_job_offers_name a $stic_job_applications_status.', '<p>Estimado/a $contact_full_name:</p>\n<p>Se ha cambiado el estado de su candidatura para la oferta laboral $stic_job_applications_stic_job_applications_stic_job_offers_name a $stic_job_applications_status.</p>', 0, '1', 0, 'notification'),
	 -- Candidatura - Notificación - Estado Aceptada
	 ('6a31f063-2d17-4fd6-aef1-9e15db0f7d11', NOW(), NOW(), '1', '1', NULL, 'Notificación - Candidatura aceptada', 'Plantilla para notificar que una candidatura ha sido aceptada.', 'Tu candidatura ha sido aceptada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $contact_full_name:\r\n\r\nNos complace informarte de que tu candidatura para la oferta laboral $stic_job_applications_stic_job_applications_stic_job_offers_name ha sido aceptada.\r\n\r\nEstado actual: $stic_job_applications_status.', '<p>Estimado/a $contact_full_name:</p>\n<p>Nos complace informarte de que tu candidatura para la oferta laboral <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha sido aceptada.</p>\n<p>Estado actual: <strong>$stic_job_applications_status</strong>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura - Notificación - Estado Rechazada o cerrada
	 ('bb6fe9c6-8b74-4526-a0a8-a7f4fd8e5960', NOW(), NOW(), '1', '1', NULL, 'Notificación - Candidatura rechazada o cerrada', 'Plantilla para notificar que una candidatura ha sido rechazada o cerrada.', 'Actualización de tu candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Estimado/a $contact_full_name:\r\n\r\nLamentamos comunicarte que tu candidatura para la oferta laboral $stic_job_applications_stic_job_applications_stic_job_offers_name ha pasado a estado $stic_job_applications_status.\r\n\r\nGracias por tu interés.', '<p>Estimado/a $contact_full_name:</p>\n<p>Lamentamos comunicarte que tu candidatura para la oferta laboral <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha pasado a estado <strong>$stic_job_applications_status</strong>.</p>\n<p>Gracias por tu interés.</p>', 0, '1', 0, 'notification'),
	 -- Oferta laboral - Notificación - Cierre vencido y estado no cerrado
	('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Notificación - Oferta con cierre vencido sin estado cerrada', 'Plantilla para notificar al responsable que la oferta tiene cierre de candidaturas a ayer y no está en estado cerrada o similar.', 'Revisar oferta laboral: cierre de candidaturas vencido - $stic_job_offers_name', 'Estimado/a,\r\n\r\nLa oferta laboral $stic_job_offers_name tiene la fecha de cierre de candidaturas vencida (ayer) y actualmente está en estado $stic_job_offers_status.\r\n\r\nPor favor, revisa la oferta y actualiza su estado si corresponde.', '<p>Estimado/a,</p>\n<p>La oferta laboral <strong>$stic_job_offers_name</strong> tiene la fecha de cierre de candidaturas vencida (ayer) y actualmente está en estado <strong>$stic_job_offers_status</strong>.</p>\n<p>Por favor, revisa la oferta y actualiza su estado si corresponde.</p>', 0, '1', 0, 'notification');

